struct Node {
    int data;           // stores the element
    struct Node *next;  // pointer to next node
};

// Using typedef for easier usage
typedef struct Node node;

// Function to create a new node
node* createNode(int value) {
    node *newNode = (node*)malloc(sizeof(node));
    if (newNode == NULL) {
        printf("Memory allocation failed\n");
        return NULL;
    }
    newNode->data = value;
    newNode->next = NULL;
    return newNode;
}

class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class SinglyLinkedList:
    def __init__(self):
        self.head = None

    def insert_at_beginning(self, value):
        new_node = Node(value)
        new_node.next = self.head  # Point new node to current head
        self.head = new_node       # Update head to new node

    def display(self):
        current = self.head
        while current:
            print(current.data, end=" -> ")
            current = current.next
        print("NULL")

# Usage
sll = SinglyLinkedList()
sll.insert_at_beginning(10)
sll.insert_at_beginning(20)
sll.insert_at_beginning(30)
sll.display()  # Output: 30 -> 20 -> 10 -> NULL

// Delete first node
void deleteFirst(node **head) {
    if (*head == NULL) {
        printf("List is empty\n");
        return;
    }
    node *temp = *head;        // Store current head
    *head = (*head)->next;     // Move head to next node
    free(temp);                // Free old head memory
}

// Delete node after a given node
void deleteAfter(node *prevNode) {
    if (prevNode == NULL || prevNode->next == NULL) {
        printf("Invalid operation\n");
        return;
    }
    node *toDelete = prevNode->next;     // Node to delete
    prevNode->next = toDelete->next;     // Bypass the node
    free(toDelete);                      // Free memory
}

// Search for an element
int search(node *head, int key) {
    int position = 1;
    node *current = head;
    while (current != NULL) {
        if (current->data == key) {
            return position;  // Found at position
        }
        current = current->next;
        position++;
    }
    return -1;  // Not found
}

public class SinglyLinkedList {
    private Node head;

    private class Node {
        int data;
        Node next;

        Node(int d) {
            data = d;
            next = null;
        }
    }

    // Insert at end
    public void insertAtEnd(int data) {
        Node newNode = new Node(data);
        if (head == null) {
            head = newNode;
            return;
        }
        Node current = head;
        while (current.next != null) {
            current = current.next;
        }
        current.next = newNode;
    }

    // Find middle element using slow and fast pointers
    public Node findMiddle() {
        Node slow = head;
        Node fast = head;

        while (fast != null && fast.next != null) {
            slow = slow.next;
            fast = fast.next.next;
        }
        return slow;
    }

    // Display list
    public void display() {
        Node current = head;
        while (current != null) {
            System.out.print(current.data + " -> ");
            current = current.next;
        }
        System.out.println("NULL");
    }

    public static void main(String[] args) {
        SinglyLinkedList list = new SinglyLinkedList();
        list.insertAtEnd(10);
        list.insertAtEnd(20);
        list.insertAtEnd(30);
        list.insertAtEnd(40);
        list.display();  // 10 -> 20 -> 30 -> 40 -> NULL

        Node middle = list.findMiddle();
        System.out.println("Middle element: " + middle.data);  // 30
    }
}
